// Declare sealed hierarchy
public sealed interface Shape 
    permits Circle, Rectangle, Triangle {
    double area();
}

public final class Circle implements Shape {
    private final double radius;
    public Circle(double radius) { this.radius = radius; }
    public double area() { return Math.PI * radius * radius; }
}

public final class Rectangle implements Shape {
    private final double w, h;
    public Rectangle(double w, double h) { this.w = w; this.h = h; }
    public double area() { return w * h; }
}

public non-sealed class Triangle implements Shape {
    // non-sealed: anyone can extend Triangle
    private final double base, height;
    public Triangle(double b, double h) { base = b; height = h; }
    public double area() { return 0.5 * base * height; }
}

// Exhaustive pattern matching (Java 21)
String describe(Shape s) {
    return switch (s) {
        case Circle c   -> "Circle r=" + c.getRadius();
        case Rectangle r -> "Rect " + r.getW() + "x" + r.getH();
        case Triangle t  -> "Triangle";
        // No default needed — compiler knows all subtypes!
    };
}

